sql:
SELECT goal_type
FROM goals
WHERE user_id = 1;

SELECT AVG(sets_completed) AS average_sets_completed
FROM workout_logs
WHERE user_id = 1 AND routine_id = 1;

external_knowledge:
- 'Squats' refers to the exercise name; 
- 'routine_id 1' refers to the first workout plan; 
- 'typical' means the average number.

- 'gardeners' refers to users with the role 'client';
- 'seeds sown' metaphorically refers to 'sets_completed' in the context of workouts;
- 'nurturing their plants in the last month' refers to completing workouts within the last 30 days.

sql:
SELECT AVG(sets_completed) AS average_sets_completed
FROM workout_logs
WHERE user_id = 1 AND exercise_id = 1;

SELECT goal_type, COUNT(*) AS goal_count
FROM goals
GROUP BY goal_type;

SELECT user_id, rating
FROM feedback
WHERE rating > 3;

SELECT exercise_name
FROM exercises
WHERE exercise_id = 1;

SELECT AVG(calories_burned_per_minute) AS average_calories
FROM exercises
WHERE difficulty_level = 'intermediate' AND is_bodyweight = 1;
